#!/usr/bin/env bash
cd "$(dirname "$(readlink -f "$0")")/.." && sudo apt-get update -qq && DEBIAN_FRONTEND=noninteractive sudo apt-get install -y build-essential cmake pkg-config curl git libudev-dev libfontconfig1-dev libxkbcommon-dev libxkbcommon-x11-dev libclang-dev llvm-dev libwayland-dev libegl1-mesa-dev libssl-dev libdbus-1-dev gettext desktop-file-utils && (command -v cargo >/dev/null || curl --proto '=https' --tlsv1.2 -sSf https://sh.rustup.rs | sh -s -- -y --default-toolchain 1.82 --profile minimal) && . "${HOME}/.cargo/env" && make X11=1 && sudo make install && sudo udevadm control --reload-rules && sudo systemctl daemon-reload && sudo systemctl try-restart asusd && systemctl --user daemon-reload && systemctl --user try-restart asusd-user
